using System;

// 1. Abstract base class
public abstract class Drawable
{
    // Abstract method: forces derived classes to implement Draw()
    public abstract void Draw();
}

// 2. Concrete implementation: Circle
public class Circle : Drawable
{
    public override void Draw()
    {
        Console.WriteLine("🔵 Drawing a circle.");
    }
}

// 3. Concrete implementation: Square
public class Square : Drawable
{
    public override void Draw()
    {
        Console.WriteLine("🟩 Drawing a square.");
    }
}

// 4. Usage example demonstrating polymorphism
public class Program
{
    public static void Main()
    {
        // Polymorphic references to the abstract type
        Drawable shape1 = new Circle();
        Drawable shape2 = new Square();

        shape1.Draw(); // Output: 🔵 Drawing a circle.
        shape2.Draw(); // Output: 🟩 Drawing a square.

        // You can also use them in collections/loops
        Drawable[] shapes = { new Circle(), new Square(), new Circle() };
        foreach (var s in shapes)
        {
            s.Draw();
        }
    }
}

